  body = bodyArg;
} else if (fileArg !== null) {
  body = readFileSync(fileArg, 'utf8');
} else if (envArg !== null) {
  body = process.env[envArg] ?? '';
} else {
  console.error('Usage: build-comment-body-json.mjs --body <text> | --from-file <path> | --from-env <NAME>');
  process.exit(1);
}

process.stdout.write(JSON.stringify({ body }));
